const SHEETS_BASE     = "https://sheets.googleapis.com/v4/spreadsheets";
const SPREADSHEET_ID  = process.env.REACT_APP_SPREADSHEET_ID || "";
const API_KEY         = process.env.REACT_APP_GOOGLE_API_KEY  || "";
const APPS_SCRIPT_URL = "https://script.google.com/macros/s/AKfycbxX6YCLAaywh3LxE0C40KH_KvHb6f68BG5nMnm_t2hrb7QaBm4WbCfMJMy6EinoKuU/exec";

export const TABS = {
  MECHANICS:    "Mechanics",
  EQUIPMENT:    "Equipment",
  WORK_ORDERS:  "WorkOrders",
  TIME_ENTRIES: "TimeEntries",
  PARTS:        "Parts",
};

// ── Read all rows (uses API Key) ──────────────────────────────
export async function readSheet(tab) {
  const url = `${SHEETS_BASE}/${SPREADSHEET_ID}/values/${tab}?key=${API_KEY}`;
  const res = await fetch(url);
  if (!res.ok) throw new Error(`Read failed: ${res.statusText}`);
  const data = await res.json();
  const [headers, ...rows] = data.values || [];
  if (!headers) return [];
  return rows.map(row =>
    Object.fromEntries(headers.map((h, i) => [h, row[i] ?? ""]))
  );
}

// ── Write via Apps Script (no auth needed) ────────────────────
async function scriptRequest(payload) {
  const res = await fetch(APPS_SCRIPT_URL, {
    method: "POST",
    headers: { "Content-Type": "text/plain" },
    body: JSON.stringify(payload),
    mode: "no-cors",
  });
  return { success: true };
}

// ── Append a new row ──────────────────────────────────────────
export async function appendRow(tab, rowObj) {
  return scriptRequest({ action: "append", tab, row: rowObj });
}

// ── Update a row by ID ────────────────────────────────────────
export async function updateRowById(tab, id, rowObj) {
  return scriptRequest({ action: "update", tab, id, row: rowObj });
}

// ── Auth helpers (kept for compatibility) ─────────────────────
export function getAuthToken()      { return sessionStorage.getItem("gapi_token"); }
export function setAuthToken(token) { sessionStorage.setItem("gapi_token", token); }
export function clearAuthToken()    { sessionStorage.removeItem("gapi_token"); }
export async function initGoogleAuth(onSuccess) { onSuccess?.(null); }
