import React, { useMemo, useState } from "react";
import { useData } from "../lib/DataContext";
import { Link } from "react-router-dom";
import { AlertTriangle, CheckCircle, Clock, Play, Square, X } from "lucide-react";
import { format, differenceInMinutes } from "date-fns";

const PRIORITY_ORDER = { High: 0, Medium: 1, Low: 2 };
const STATUS_OPTIONS  = ["Pending", "In Progress", "Completed", "Cancelled"];
const EQ_STATUSES     = ["Active", "In Repair", "Inactive"];

function priorityColor(p) {
  return p === "High" ? "var(--danger)" : p === "Medium" ? "var(--warn)" : "var(--success)";
}
function statusColor(s) {
  return s === "Completed" ? "var(--success)" : s === "In Progress" ? "var(--info)" : s === "Pending" ? "var(--warn)" : "var(--danger)";
}
function eqStatusColor(s) {
  return s === "Active" ? "var(--success)" : s === "In Repair" ? "var(--warn)" : "var(--danger)";
}

function LiveTimer({ clockIn }) {
  const [elapsed, setElapsed] = React.useState("");
  React.useEffect(() => {
    const tick = () => {
      const mins = differenceInMinutes(new Date(), new Date(clockIn));
      const h = Math.floor(mins / 60);
      const m = mins % 60;
      setElapsed(`${h}h ${m.toString().padStart(2, "0")}m`);
    };
    tick();
    const id = setInterval(tick, 30000);
    return () => clearInterval(id);
  }, [clockIn]);
  return <span className="pulse" style={{ color: "var(--success)", fontFamily: "var(--font-mono)", fontSize: 12 }}>● {elapsed}</span>;
}

function ClockInModal({ workOrder, mechanics, onClose, onSave }) {
  const [mechanicId, setMechanicId] = useState(mechanics[0]?.id || "");
  return (
    <div className="modal-overlay" onClick={e => e.target === e.currentTarget && onClose()}>
      <div className="modal" style={{ maxWidth: 420 }}>
        <div className="modal-header">
          <span className="modal-title" style={{ color: "var(--success)" }}>⏱ Clock In</span>
          <button className="btn btn-icon btn-ghost" onClick={onClose}><X size={18} /></button>
        </div>
        <div className="modal-body">
          <div style={{ padding: 14, background: "var(--bg3)", borderRadius: "var(--radius)", marginBottom: 4 }}>
            <div style={{ fontWeight: 600, fontSize: 15, marginBottom: 2 }}>{workOrder.equipmentName}</div>
            <div style={{ fontSize: 13, color: "var(--text2)", marginBottom: 4 }}>{workOrder.title}</div>
            <div style={{ fontSize: 12, fontFamily: "var(--font-mono)", color: "var(--text3)" }}>{workOrder.id}</div>
          </div>
          <div className="form-group">
            <label className="form-label">Mechanic</label>
            <select className="form-input" value={mechanicId} onChange={e => setMechanicId(e.target.value)}>
              {mechanics.filter(m => m.active === "true").map(m => (
                <option key={m.id} value={m.id}>{m.name}</option>
              ))}
            </select>
          </div>
          <div style={{ padding: "10px 14px", background: "rgba(26,158,92,0.08)", border: "1px solid rgba(26,158,92,0.2)", borderRadius: "var(--radius)", fontSize: 13, color: "var(--success)", fontFamily: "var(--font-mono)" }}>
            Start time: {format(new Date(), "HH:mm:ss")}
          </div>
        </div>
        <div className="modal-footer">
          <button className="btn btn-ghost" onClick={onClose}>Cancel</button>
          <button className="btn btn-success" onClick={() => onSave({ mechanicId, workOrderId: workOrder.id })}>
            <Play size={14} /> Start
          </button>
        </div>
      </div>
    </div>
  );
}

function ClockOutModal({ entry, workOrder, onClose, onSave }) {
  const [notes, setNotes]               = useState("");
  const [updateStatus, setUpdateStatus] = useState(false);
  const [newStatus, setNewStatus]       = useState(workOrder?.status || "In Progress");
  const [updateEq, setUpdateEq]         = useState(false);
  const [eqStatus, setEqStatus]         = useState("Active");

  return (
    <div className="modal-overlay" onClick={e => e.target === e.currentTarget && onClose()}>
      <div className="modal" style={{ maxWidth: 500 }}>
        <div className="modal-header">
          <span className="modal-title" style={{ color: "var(--danger)" }}>⏹ Clock Out</span>
          <button className="btn btn-icon btn-ghost" onClick={onClose}><X size={18} /></button>
        </div>
        <div className="modal-body">
          {/* Summary */}
          <div style={{ padding: 14, background: "var(--bg3)", borderRadius: "var(--radius)", marginBottom: 4 }}>
            <div style={{ fontWeight: 600, fontSize: 15, marginBottom: 2 }}>{entry.mechanicName}</div>
            <div style={{ fontSize: 13, color: "var(--text2)", marginBottom: 4 }}>
              {workOrder?.equipmentName} — {workOrder?.title}
            </div>
            <div style={{ fontSize: 12, color: "var(--text3)", fontFamily: "var(--font-mono)", marginBottom: 6 }}>
              {entry.workOrderId} · Started: {entry.clockIn?.split(" ")[1]}
            </div>
            <LiveTimer clockIn={entry.clockIn} />
          </div>

          {/* Notes */}
          <div className="form-group">
            <label className="form-label">Work Notes</label>
            <textarea className="form-input" rows={2} value={notes} onChange={e => setNotes(e.target.value)} placeholder="What was done?" />
          </div>

          {/* Update order status */}
          <div style={{ borderTop: "1px solid var(--border)", paddingTop: 14 }}>
            <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", marginBottom: 10 }}>
              <span style={{ fontWeight: 500, fontSize: 13 }}>✅ Update Order Status?</span>
              <div style={{ display: "flex", gap: 6 }}>
                <button type="button" className={"btn btn-sm " + (updateStatus ? "btn-primary" : "btn-ghost")} onClick={() => setUpdateStatus(true)}>Yes</button>
                <button type="button" className={"btn btn-sm " + (!updateStatus ? "btn-primary" : "btn-ghost")} onClick={() => setUpdateStatus(false)}>No</button>
              </div>
            </div>
            {updateStatus && (
              <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 6, marginBottom: 14 }}>
                {STATUS_OPTIONS.map(s => (
                  <button key={s} type="button" onClick={() => setNewStatus(s)} style={{
                    padding: "8px 10px", borderRadius: "var(--radius)",
                    border: newStatus === s ? "2px solid var(--accent)" : "1px solid var(--border2)",
                    background: newStatus === s ? "rgba(232,130,10,0.1)" : "var(--bg3)",
                    color: newStatus === s ? "var(--accent)" : "var(--text2)",
                    fontWeight: newStatus === s ? 600 : 400,
                    fontSize: 12, cursor: "pointer",
                  }}>
                    {s === "Completed" && "✓ "}{s === "In Progress" && "⚙ "}{s === "Pending" && "⏳ "}{s === "Cancelled" && "✕ "}{s}
                  </button>
                ))}
              </div>
            )}
          </div>

          {/* Update equipment status */}
          <div style={{ borderTop: "1px solid var(--border)", paddingTop: 14 }}>
            <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", marginBottom: 10 }}>
              <span style={{ fontWeight: 500, fontSize: 13 }}>🔧 Update Equipment Status?</span>
              <div style={{ display: "flex", gap: 6 }}>
                <button type="button" className={"btn btn-sm " + (updateEq ? "btn-primary" : "btn-ghost")} onClick={() => setUpdateEq(true)}>Yes</button>
                <button type="button" className={"btn btn-sm " + (!updateEq ? "btn-primary" : "btn-ghost")} onClick={() => setUpdateEq(false)}>No</button>
              </div>
            </div>
            {updateEq && (
              <div style={{ display: "flex", gap: 6 }}>
                {EQ_STATUSES.map(s => (
                  <button key={s} type="button" onClick={() => setEqStatus(s)} style={{
                    flex: 1, padding: "8px 6px", borderRadius: "var(--radius)",
                    border: eqStatus === s ? `2px solid ${eqStatusColor(s)}` : "1px solid var(--border2)",
                    background: eqStatus === s ? `${eqStatusColor(s)}18` : "var(--bg3)",
                    color: eqStatus === s ? eqStatusColor(s) : "var(--text3)",
                    fontWeight: eqStatus === s ? 600 : 400,
                    fontSize: 12, cursor: "pointer",
                  }}>
                    {s === "Active" && "✓ "}{s === "In Repair" && "⚙ "}{s === "Inactive" && "✕ "}{s}
                  </button>
                ))}
              </div>
            )}
          </div>
        </div>
        <div className="modal-footer">
          <button className="btn btn-ghost" onClick={onClose}>Cancel</button>
          <button className="btn btn-danger" onClick={() => onSave(entry.id, notes, updateStatus ? newStatus : null, updateEq ? eqStatus : null)}>
            <Square size={14} /> Clock Out
          </button>
        </div>
      </div>
    </div>
  );
}

export default function Dashboard() {
  const { workOrders, equipment, timeEntries, mechanics, clockIn, clockOut, updateWorkOrder, updateEquipment, loading } = useData();
  const [clockInOrder,  setClockInOrder]  = useState(null);
  const [clockOutEntry, setClockOutEntry] = useState(null);

  // Open orders sorted by priority
  const openOrders = useMemo(() => {
    return workOrders
      .filter(w => w.status !== "Completed" && w.status !== "Cancelled")
      .sort((a, b) => (PRIORITY_ORDER[a.priority] ?? 2) - (PRIORITY_ORDER[b.priority] ?? 2));
  }, [workOrders]);

  const activeEntries = useMemo(() =>
    timeEntries.filter(t => t.clockIn && !t.clockOut),
    [timeEntries]
  );

  const stats = useMemo(() => {
    const urgent   = openOrders.filter(w => w.priority === "High").length;
    const active   = equipment.filter(e => e.status === "Active").length;
    const totalHrs = timeEntries.reduce((sum, t) => sum + (parseFloat(t.hours) || 0), 0);
    return { open: openOrders.length, urgent, active, clocked: activeEntries.length, totalHrs: totalHrs.toFixed(1) };
  }, [openOrders, equipment, timeEntries, activeEntries]);

  // Check if a work order has an active clock in
  const isClocked = (woId) => activeEntries.some(t => t.workOrderId === woId);

  const handleClockIn = async ({ mechanicId, workOrderId }) => {
    await clockIn({ mechanicId, workOrderId });
    setClockInOrder(null);
  };

  const handleClockOut = async (entryId, notes, newStatus, newEqStatus) => {
    await clockOut(entryId, notes);
    const entry = timeEntries.find(t => t.id === entryId);
    if (entry) {
      const wo = workOrders.find(w => w.id === entry.workOrderId);
      if (newStatus && wo) await updateWorkOrder({ ...wo, status: newStatus });
      if (newEqStatus && wo) {
        const eq = equipment.find(e => e.id === wo.equipmentId);
        if (eq) await updateEquipment({ ...eq, status: newEqStatus });
      }
    }
    setClockOutEntry(null);
  };

  if (loading) return <div className="empty-state"><p>Loading...</p></div>;

  return (
    <div>
      <div className="page-header">
        <div>
          <h1 className="page-title">Dashboard</h1>
          <p className="page-subtitle">{format(new Date(), "EEEE, MMMM d yyyy")}</p>
        </div>
        <Link to="/orders" className="btn btn-primary">+ New Order</Link>
      </div>

      {/* KPIs */}
      <div className="grid-4 mb-24">
        <div className="stat-card" style={{ "--accent-line": "var(--warn)" }}>
          <span className="stat-label">Open Orders</span>
          <span className="stat-value">{stats.open}</span>
          <span className="stat-sub">{stats.urgent} high priority</span>
        </div>
        <div className="stat-card" style={{ "--accent-line": "var(--danger)" }}>
          <span className="stat-label">High Priority</span>
          <span className="stat-value">{stats.urgent}</span>
          <span className="stat-sub">need attention</span>
        </div>
        <div className="stat-card" style={{ "--accent-line": "var(--success)" }}>
          <span className="stat-label">Active Equipment</span>
          <span className="stat-value">{stats.active}</span>
          <span className="stat-sub">of {equipment.length} total</span>
        </div>
        <div className="stat-card" style={{ "--accent-line": "var(--info)" }}>
          <span className="stat-label">Total Hours</span>
          <span className="stat-value">{stats.totalHrs}</span>
          <span className="stat-sub">{stats.clocked} active now</span>
        </div>
      </div>

      {/* Open Orders by Priority — main section */}
      <div className="card mb-24">
        <div className="card-header">
          <span className="card-title">Open Work Orders — By Priority</span>
          <Link to="/orders" className="btn btn-ghost btn-sm">View all</Link>
        </div>

        {openOrders.length === 0 ? (
          <div className="empty-state" style={{ padding: 30 }}>
            <CheckCircle size={32} />
            <p>No open work orders!</p>
          </div>
        ) : (
          <div style={{ display: "flex", flexDirection: "column", gap: 10 }}>
            {openOrders.map(wo => {
              const active = isClocked(wo.id);
              const activeEntry = activeEntries.find(t => t.workOrderId === wo.id);
              return (
                <div key={wo.id} style={{
                  display: "flex",
                  alignItems: "center",
                  gap: 14,
                  padding: "14px 16px",
                  background: "var(--bg3)",
                  borderRadius: "var(--radius-lg)",
                  borderLeft: `4px solid ${priorityColor(wo.priority)}`,
                  transition: "all 0.15s",
                }}>
                  {/* Priority dot */}
                  <div style={{
                    width: 10, height: 10, borderRadius: "50%",
                    background: priorityColor(wo.priority),
                    flexShrink: 0,
                  }} />

                  {/* Info */}
                  <div style={{ flex: 1, minWidth: 0 }}>
                    <div style={{ fontWeight: 600, fontSize: 14, marginBottom: 2 }}>
                      {wo.equipmentName}
                      <span style={{ fontWeight: 400, color: "var(--text2)", marginLeft: 8, fontSize: 13 }}>
                        — {wo.title}
                      </span>
                    </div>
                    <div style={{ display: "flex", gap: 12, fontSize: 12, color: "var(--text3)", flexWrap: "wrap" }}>
                      <span style={{ fontFamily: "var(--font-mono)" }}>{wo.id}</span>
                      <span style={{ color: priorityColor(wo.priority), fontWeight: 600 }}>{wo.priority}</span>
                      <span style={{ color: statusColor(wo.status) }}>{wo.status}</span>
                      {active && activeEntry && <LiveTimer clockIn={activeEntry.clockIn} />}
                    </div>
                  </div>

                  {/* Clock In / Clock Out button */}
                  {!active ? (
                    <button
                      className="btn btn-success btn-sm"
                      onClick={() => setClockInOrder(wo)}
                      style={{ flexShrink: 0 }}
                    >
                      <Play size={13} /> Clock In
                    </button>
                  ) : (
                    <div style={{ display: "flex", alignItems: "center", gap: 8, flexShrink: 0 }}>
                      <LiveTimer clockIn={activeEntry.clockIn} />
                      <button
                        className="btn btn-danger btn-sm"
                        onClick={() => setClockOutEntry(activeEntry)}
                      >
                        <Square size={13} /> Clock Out
                      </button>
                    </div>
                  )}
                </div>
              );
            })}
          </div>
        )}
      </div>

      <div className="grid-2" style={{ gap: 20 }}>
        {/* Active now */}
        <div className="card">
          <div className="card-header">
            <span className="card-title">Working Now</span>
            <span className="badge badge-success pulse">{activeEntries.length}</span>
          </div>
          {activeEntries.length === 0 ? (
            <div className="empty-state" style={{ padding: 24 }}>
              <Clock size={28} />
              <p>No one clocked in</p>
            </div>
          ) : (
            <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
              {activeEntries.map(te => (
                <div key={te.id} style={{
                  padding: "10px 14px", background: "var(--bg3)",
                  borderRadius: "var(--radius)", borderLeft: "2px solid var(--success)",
                  display: "flex", justifyContent: "space-between", alignItems: "center"
                }}>
                  <div>
                    <div style={{ fontWeight: 600, fontSize: 14 }}>{te.mechanicName}</div>
                    <div style={{ fontSize: 11, color: "var(--text3)", fontFamily: "var(--font-mono)" }}>{te.workOrderId}</div>
                  </div>
                  <LiveTimer clockIn={te.clockIn} />
                </div>
              ))}
            </div>
          )}
        </div>

        {/* Equipment alerts */}
        <div className="card">
          <div className="card-header">
            <span className="card-title">Equipment Alerts</span>
          </div>
          <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
            {equipment.filter(e => e.status === "In Repair" || e.status === "Inactive").length === 0 ? (
              <div style={{ display: "flex", alignItems: "center", gap: 10, color: "var(--success)", fontSize: 13 }}>
                <CheckCircle size={16} />All equipment operational
              </div>
            ) : (
              equipment.filter(e => e.status === "In Repair" || e.status === "Inactive").map(eq => (
                <div key={eq.id} style={{
                  display: "flex", alignItems: "center", gap: 12,
                  padding: "10px 14px", background: "var(--bg3)",
                  borderRadius: "var(--radius)",
                  borderLeft: `2px solid ${eq.status === "In Repair" ? "var(--warn)" : "var(--danger)"}`
                }}>
                  <AlertTriangle size={14} color={eq.status === "In Repair" ? "var(--warn)" : "var(--danger)"} />
                  <div>
                    <div style={{ fontSize: 13, fontWeight: 500 }}>{eq.name}</div>
                    <div style={{ fontSize: 11, color: "var(--text3)", fontFamily: "var(--font-mono)" }}>{eq.status}</div>
                  </div>
                </div>
              ))
            )}
          </div>
        </div>
      </div>

      {clockInOrder && (
        <ClockInModal
          workOrder={clockInOrder}
          mechanics={mechanics}
          onClose={() => setClockInOrder(null)}
          onSave={handleClockIn}
        />
      )}

      {clockOutEntry && (
        <ClockOutModal
          entry={clockOutEntry}
          workOrder={workOrders.find(w => w.id === clockOutEntry.workOrderId)}
          onClose={() => setClockOutEntry(null)}
          onSave={handleClockOut}
        />
      )}
    </div>
  );
}
